# board.py

"""
Represents the Checkers board.
"""

class Board:
    def __init__(self):
        self.board = [[' ' for _ in range(8)] for _ in range(8)]
        self.initialize_pieces()

    def initialize_pieces(self):
        # Initialize pieces for both players
        for i in range(3):
            for j in (1, 3, 5, 7):
                if (i + j) % 2 == 0:
                    self.board[i][j] = 'b'
        for i in range(5, 8):
            for j in (0, 2, 4, 6):
                if (i + j) % 2 == 0:
                    self.board[i][j] = 'r'

    def print_board(self):
        for row in self.board:
            print(' '.join(row))

    def get_piece_at(self, x, y):
        return self.board[x][y]

    def move_piece(self, from_x, from_y, to_x, to_y):
        piece = self.get_piece_at(from_x, from_y)
        if piece != ' ':
            self.board[from_x][from_y] = ' '
            self.board[to_x][to_y] = piece
```

