        self.board = Board()
        self.current_player = 'b'

    def print_board(self):
        self.board.print_board()

    def switch_player(self):
        self.current_player = 'r' if self.current_player == 'b' else 'b'

    def is_valid_move(self, from_x, from_y, to_x, to_y):
        piece = self.board.get_piece_at(from_x, from_y)
        if piece != self.current_player and piece != self.current_player.upper():
            return False

        # Simple movement for now
        return (abs(to_x - from_x), abs(to_y - from_y)) == (1, 1)

    def make_move(self, from_x, from_y, to_x, to_y):
        if self.is_valid_move(from_x, from_y, to_x, to_y):
            self.board.move_piece(from_x, from_y, to_x, to_y)
            self.switch_player()

